func PackSourceOneOfDiscriminator(input map[string]any) string {
	if collector, ok := input["collector"].(map[string]any); ok {
		if value, ok := collector["type"].(string); ok {
			return value
		}
	}
	if value, ok := input["type"].(string); ok {
		return value
	}
	return ""
}
